import{_ as a,o,c as r,a2 as n}from"./chunks/framework.BQ1gajhD.js";const g=JSON.parse('{"title":"五方亭","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/jingshan/wufang-ting.md","filePath":"landmarks/jingshan/wufang-ting.md","lastUpdated":1784720050000}'),d={name:"landmarks/jingshan/wufang-ting.md"};function e(l,t,i,s,u,h){return o(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="五方亭" tabindex="-1">五方亭 <a class="header-anchor" href="#五方亭" aria-label="Permalink to &quot;五方亭&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1621163771613-bd0a06ceb600?w=1200&amp;q=80" alt="景山五方亭"></p><blockquote><p>&quot;一亭一世界，五亭五方天。金木水火土，东西南北方。站在五方亭下，仿佛能听见历史在檐角间低语。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>景山五方亭是景山山脊线上从东到西依次排列的五座亭阁，分别是：周赏亭、观妙亭、万春亭、辑芳亭、富览亭。这五座亭子不仅构成了景山最鲜明的天际线轮廓，也暗含着中国古代&quot;五行&quot;（金木水火土）与&quot;五方&quot;（东西南北中）的宇宙哲学观念。</p><p>五方亭的建筑风格统一而各有特色：万春亭为黄琉璃瓦重檐攒尖顶，等级最高，对应&quot;土&quot;与&quot;中&quot;；其余四座亭子均为绿琉璃瓦单檐攒尖顶，分别对应五行中的金、木、水、火与五方中的东、西、南、北。五座亭子在色彩上形成了黄绿相间的视觉效果，与周围的红墙古树、蓝天白云构成了一幅极具中国传统美学意境的画面。</p><p>每年春季，五方亭下的牡丹园花开似锦，&quot;景山牡丹节&quot;吸引了无数游人前来观赏，使这里成为北京春季赏花的热门目的地之一。</p><hr><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><h3 id="五方亭一览" tabindex="-1">五方亭一览 <a class="header-anchor" href="#五方亭一览" aria-label="Permalink to &quot;五方亭一览&quot;">​</a></h3><table tabindex="0"><thead><tr><th>亭名</th><th>位置</th><th>屋顶形制</th><th>对应五行</th><th>对应五方</th></tr></thead><tbody><tr><td><strong>周赏亭</strong></td><td>最东侧</td><td>绿琉璃瓦单檐攒尖顶</td><td>木</td><td>东</td></tr><tr><td><strong>观妙亭</strong></td><td>东侧</td><td>绿琉璃瓦单檐攒尖顶</td><td>火</td><td>南</td></tr><tr><td><strong>万春亭</strong></td><td>正中</td><td>黄琉璃瓦重檐攒尖顶</td><td>土</td><td>中</td></tr><tr><td><strong>辑芳亭</strong></td><td>西侧</td><td>绿琉璃瓦单檐攒尖顶</td><td>金</td><td>西</td></tr><tr><td><strong>富览亭</strong></td><td>最西侧</td><td>绿琉璃瓦单檐攒尖顶</td><td>水</td><td>北</td></tr></tbody></table><h3 id="建筑细节" tabindex="-1">建筑细节 <a class="header-anchor" href="#建筑细节" aria-label="Permalink to &quot;建筑细节&quot;">​</a></h3><p><strong>万春亭</strong>（主亭）：</p><ul><li>黄琉璃瓦重檐攒尖顶，是五方亭中等级最高的建筑</li><li>亭内原供奉铜铸佛像，现无存</li><li>亭额&quot;万春亭&quot;为乾隆御笔</li><li>站在亭上可俯瞰故宫全景，是北京最经典的观景位置</li></ul><p><strong>周赏亭、观妙亭、辑芳亭、富览亭</strong>（副亭）：</p><ul><li>绿琉璃瓦单檐攒尖顶，形制统一而简洁</li><li>每座亭子的匾额均为乾隆皇帝亲题</li><li>亭内原各供奉有佛像，现无存</li><li>亭内外的彩画和斗拱工艺精湛，值得细细观赏</li></ul><h3 id="彩画与匾额" tabindex="-1">彩画与匾额 <a class="header-anchor" href="#彩画与匾额" aria-label="Permalink to &quot;彩画与匾额&quot;">​</a></h3><p>五方亭的彩画采用典型的清代官式彩画技法，以旋子彩画为主，辅以苏式彩画。彩画的题材丰富多样，包括龙凤、花卉、云纹等，色彩鲜艳而不失典雅。每座亭子的匾额均为乾隆皇帝亲笔题写，字体工整有力，是清代书法艺术的珍贵遗存。</p><hr><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="乾隆与五方亭" tabindex="-1">乾隆与五方亭 <a class="header-anchor" href="#乾隆与五方亭" aria-label="Permalink to &quot;乾隆与五方亭&quot;">​</a></h3><p>五方亭的格局定型于清乾隆年间。乾隆皇帝一生六次南巡，对江南园林情有独钟，但他对景山这座皇家御苑的修缮也极为用心。五方亭的重建和布局，体现了乾隆对&quot;天人合一&quot;哲学思想的追求。</p><p>&quot;周赏&quot;&quot;观妙&quot;&quot;辑芳&quot;&quot;富览&quot;四个亭名，均出自古典文献，寓意深远。&quot;周赏&quot;意为遍览美景，&quot;观妙&quot;意为观察精妙，&quot;辑芳&quot;意为汇聚芳华，&quot;富览&quot;则取&quot;富有四海，一览无遗&quot;之意。这些亭名不仅文雅优美，也暗含了帝王胸怀天下的气度。</p><h3 id="五方佛的传说" tabindex="-1">五方佛的传说 <a class="header-anchor" href="#五方佛的传说" aria-label="Permalink to &quot;五方佛的传说&quot;">​</a></h3><p>五方亭的另一种解读，是与佛教中的&quot;五方佛&quot;相对应。五方佛是佛教密宗中的重要概念，分别代表五个方位的佛：东方阿閦佛、南方宝生佛、中央大日如来、西方阿弥陀佛、北方不空成就佛。</p><p>有学者认为，景山五方亭内原供奉的五尊佛像，正是对应五方佛，这体现了清代统治者&quot;以佛教巩固统治&quot;的宗教政策。五方亭因此不仅是观景的建筑，也具有了宗教祭祀的功能。不过，这一说法仍有待进一步的考证。</p><hr><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><p><strong>建筑对称美学</strong>：五座亭子沿山脊一字排开，黄绿相间，层次分明，是中国传统建筑对称美学的典范。无论从山下仰望，还是从万春亭俯瞰，都能感受到这种建筑布局的精妙之处。</p></li><li><p><strong>春季牡丹展</strong>：每年4月中旬至5月中旬，五方亭下的牡丹园花开似锦。景山牡丹以&quot;景山牡丹&quot;品牌闻名，品种多达数百种，包括姚黄、魏紫、赵粉、豆绿等传统名品。牡丹节期间，公园内还会举办各种文化活动，热闹非凡。</p></li><li><p><strong>秋季银杏</strong>：五方亭周围种植了大量银杏树，每到深秋，金黄的银杏叶与红墙黄瓦相映成趣，是摄影爱好者的天堂。</p></li><li><p><strong>彩画与匾额细节</strong>：五方亭内的彩画和匾额是清代艺术的精品，值得细细观赏。尤其是万春亭内的彩画，保存相对完好，可以近距离感受清代宫廷艺术的精湛工艺。</p></li></ol><hr><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>最佳路线</strong>：从万春亭向西依次游览辑芳亭、富览亭，再向东返回游览观妙亭、周赏亭，可完整欣赏五方亭全景。</li><li><strong>春季高峰</strong>：牡丹节期间（4月中旬-5月中旬）游人众多，建议工作日或清晨前往，避开高峰。</li><li><strong>摄影建议</strong>：清晨和傍晚的光线最适合拍摄五方亭的剪影和全景；广角镜头可捕捉五亭连珠的壮阔画面。</li><li><strong>文化内涵</strong>：建议参观前了解&quot;五行&quot;&quot;五方&quot;&quot;五方佛&quot;等相关文化背景，可大大增加游览的趣味性和深度。</li><li><strong>穿着建议</strong>：景山山脊风较大，春秋季节建议携带外套。</li></ul><hr><p><strong>📍 位置</strong>：景山公园山脊线上，从万春亭向东西两侧延伸</p><p><strong>⏱️ 建议游览</strong>：30-40分钟</p><p><strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/jingshan/">景山公园概览</a></p>',36)])])}const p=a(d,[["render",e]]);export{g as __pageData,p as default};
